SELECT gs.* FROM game_session gs
LEFT JOIN script s ON gs.script_id = s.id


        AND s.script_name LIKE CONCAT('%', #{keyword}, '%')




                AND UPPER(gs.status) IN ('ONGOING', 'IN_PROGRESS')


                AND gs.status = #{status}




        AND gs.start_time >= #{startDate}


        AND gs.end_time <= #{endDate}


ORDER BY IFNULL(gs.updated_at, gs.created_at) DESC, gs.id DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM game_session gs
LEFT JOIN script s ON gs.script_id = s.id


        AND s.script_name LIKE CONCAT('%', #{keyword}, '%')




                AND UPPER(gs.status) IN ('ONGOING', 'IN_PROGRESS')


                AND gs.status = #{status}




        AND gs.start_time >= #{startDate}


        AND gs.end_time <= #{endDate}

