UPDATE game_session
script_id = #{scriptId}, dm_id = #{dmId}, start_time = #{startTime}, end_time = #{endTime}, status = #{status}, max_players = #{maxPlayers}, current_players = #{currentPlayers},
WHERE id = #{id}
